#include <bits/stdc++.h>
using namespace std;

const int N=2e4+10,M=2e5+N*2,INF=1e8;

int n,m,t;
int head[N],ver[M],edge[M],nxt[M],tot=1;
int S,T,d[N],now[N],q[N];
int dfn[N],low[N],num,stk[N],top,c[N],cnt;
bool ins[N];
vector<int> e[N],ans;

void add(int x,int y){
    ver[++tot]=y,edge[tot]=1,nxt[tot]=head[x],head[x]=tot;
    ver[++tot]=x,edge[tot]=0,nxt[tot]=head[y],head[y]=tot;
}

bool bfs(){
    memset(d,0,sizeof(d));
    d[S]=1,now[S]=head[S];
    int hh=1,tt=0;
    q[++tt]=S;
    while(hh<=tt){
        int x=q[hh++];
        for(int i=head[x],y;i;i=nxt[i])
            if(edge[i] && !d[y=ver[i]]){
                d[y]=d[x]+1,now[y]=head[y];
                if(y==T)
                    return true;
                q[++tt]=y;
            }
    }
    return false;
}

int Dinic(int x,int flow){
    if(x==T)
        return flow;
    int res=0;
    for(int i=now[x],y;i && res<flow;i=nxt[i]){
        y=ver[i],now[x]=i;
        if(d[y]==d[x]+1 && edge[i]){
            int tmp=Dinic(y,min(flow-res,edge[i]));
            if(!tmp) d[y]=0;
            edge[i]-=tmp,edge[i^1]+=tmp;
            res+=tmp;
        }
    }
    return res;
}

void tarjan(int x){
    dfn[x]=low[x]=++num;
    stk[++top]=x,ins[x]=1;
    for(int y:e[x])
        if(!dfn[y]){
            tarjan(y);
            low[x]=min(low[x],low[y]);
        }else if(ins[y])
            low[x]=min(low[x],dfn[y]);
    if(dfn[x]==low[x]){
        cnt++;
        int z;
        do{
            z=stk[top--],c[z]=cnt,ins[z]=0;
        }while(z!=x);
    }
}

int main(){
    //freopen("main.in","r",stdin);
    scanf("%d%d%d",&n,&m,&t);
    for(int i=1;i<=t;i++){
        int a,b;
        scanf("%d%d",&a,&b);
        add(a,n+b);
    }
    S=n+m+1,T=n+m+2;
    for(int i=1;i<=n;i++)
        add(S,i);
    for(int i=1;i<=m;i++)
        add(n+i,T);
    while(bfs())
        while(Dinic(S,INF));
    for(int i=2;i<=tot;i++)
        if(edge[i])
            e[ver[i^1]].push_back(ver[i]);
    for(int i=1;i<=n+m+2;i++)
        if(!dfn[i])
            tarjan(i);
    for(int i=1;i<=t;i++)
        if(edge[i*2] && c[ver[i*2]]!=c[ver[i*2+1]])
            ans.push_back(i);
    printf("%d\n",ans.size());
    for(int i:ans)
        printf("%d ",i);
    return 0;
}
